mapper.select:
SELECT p.*, ch.channel_name AS matched_channel_name_join
FROM jst_sales_pre_register p
LEFT JOIN jst_channel ch ON p.matched_channel_id = ch.channel_id AND ch.del_flag = '0'

    AND p.sales_id = #{salesId}
    AND p.phone = #{phone}
    AND p.status = #{status}

ORDER BY p.create_time DESC

